const titlesRaw = '{{PERSON_TITLES}}';
const locationsRaw = '{{PERSON_LOCATIONS}}';
const keywordsRaw = '{{KEYWORDS}}';
const rangesRaw = '{{EMPLOYEE_RANGES}}';
const toArr = (s) => s.split('|').map(v => v.trim()).filter(Boolean);
const body = { per_page: 25, page: 1 };
const titles = toArr(titlesRaw);
if (titles.length) body.person_titles = titles;
const locations = toArr(locationsRaw);
if (locations.length) body.person_locations = locations;
const keywords = toArr(keywordsRaw);
if (keywords.length) body.q_keywords = keywords.join(' ');
const ranges = toArr(rangesRaw);
if (ranges.length) body.organization_num_employees_ranges = ranges;
return [{ json: body }];

const data = $input.first().json;
const people = data.people || [];
const results = people.slice(0, 25).map(p => ({
  apolloId: p.id,
  firstName: p.first_name || '',
  lastName: p.last_name || '',
  name: p.name || '',
  title: p.title || '',
  city: p.city || '',
  state: p.state || '',
  country: p.country || '',
  companyName: p.organization?.name || '',
  companyWebsite: p.organization?.website_url || '',
  industry: p.organization?.industry || '',
  employeeCount: p.organization?.estimated_num_employees || 0
}));
return results.map(r => ({ json: r }));

const apiKey = '{{APOLLO_API_KEY}}';
const results = [];
for (const item of $input.all()) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.apollo.io/api/v1/people/match',
      headers: { 'X-Api-Key': apiKey, 'Content-Type': 'application/json' },
      body: { id: item.json.apolloId, reveal_personal_emails: true },
      json: true
    });
    const p = res.person;
    if (!p) continue;
    const email = p.email || (p.personal_emails && p.personal_emails[0]) || '';
    if (!email) continue;
    results.push({ json: {
      apolloId: p.id,
      firstName: p.first_name || '',
      lastName: p.last_name || '',
      name: p.name || '',
      title: p.title || '',
      email: email,
      phone: (p.phone_numbers && p.phone_numbers[0]?.sanitized_number) || '',
      companyName: p.organization?.name || '',
      industry: p.organization?.industry || '',
      employeeCount: p.organization?.estimated_num_employees || 0
    } });
  } catch (e) { /* skip failed enrichments */ }
  await new Promise(r => setTimeout(r, 500));
}
return results;

const saved = $input.first().json;
const contactId = saved.id || saved.contactId || '';
const e = saved._enriched || saved;
const template = '{{AGENT_PROMPT}}';
const message = template
  .replace(/\{\{firstName\}\}/g, e.firstName || '')
  .replace(/\{\{title\}\}/g, e.title || '')
  .replace(/\{\{companyName\}\}/g, e.companyName || '');
return [{ json: { contactId, name: e.name, email: e.email, phone: e.phone, title: e.title, companyName: e.companyName, industry: e.industry, source: 'apollo', message, firstName: e.firstName } }];
